package com.example.webhookhandler.controller;

import com.example.webhookhandler.model.WebhookRequest;
import com.example.webhookhandler.model.WebhookResponse;
import com.example.webhookhandler.service.ContentFetchService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/webhooks")
public class WebhookController {

    private final ContentFetchService contentFetchService;

    public WebhookController(ContentFetchService contentFetchService) {
        this.contentFetchService = contentFetchService;
    }

    @PostMapping("/fetch")
    public ResponseEntity<WebhookResponse> handleWebhook(@RequestBody WebhookRequest request) {
        if (request == null || request.getUrl() == null || request.getUrl().isBlank()) {
            return ResponseEntity.badRequest().body(new WebhookResponse(false, "Missing url", null));
        }

        try {
            String content = contentFetchService.fetchContent(request.getUrl());
            return ResponseEntity.ok(new WebhookResponse(true, "Fetched successfully", content));
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().body(new WebhookResponse(false, e.getMessage(), null));
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(new WebhookResponse(false, "Failed to fetch content", null));
        }
    }
}

