package com.example.webhookhandler.service;

import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.net.URI;

@Service
public class ContentFetchService {

    private final RestTemplate restTemplate;

    public ContentFetchService(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    public String fetchContent(String url) {
        validateUrl(url);

        ResponseEntity<String> response = restTemplate.getForEntity(URI.create(url), String.class);
        if (!response.getStatusCode().is2xxSuccessful()) {
            throw new IllegalStateException("Non-success response: " + response.getStatusCode());
        }
        return response.getBody();
    }

    private void validateUrl(String url) {
        try {
            URI uri = URI.create(url);
            String scheme = uri.getScheme();
            if (scheme == null || !(scheme.equalsIgnoreCase("http") || scheme.equalsIgnoreCase("https"))) {
                throw new IllegalArgumentException("Only http and https URLs are allowed");
            }
            if (uri.getHost() == null || uri.getHost().isBlank()) {
                throw new IllegalArgumentException("Invalid URL host");
            }
        } catch (IllegalArgumentException e) {
            throw e;
        } catch (Exception e) {
            throw new IllegalArgumentException("Invalid URL");
        }
    }
}